function resolveMultiLineConcat(lines, startIdx) {
  const strings = [];
  let i = startIdx;

  const extractStrings = (line) => {
    const matches = [...line.matchAll(/"(?:[^"\\]|\\.)*"|'(?:[^'\\]|\\.)*'/g)];
    return matches.map((m) => m[0].slice(1, -1));
  };

  const firstParts = extractStrings(lines[i]);
  if (firstParts.length === 0) return null;
  strings.push(...firstParts);

  if (!/\+\s*(?:\/\/.*)?$/.test(lines[i])) return null;

  i++;

  while (i < lines.length) {
    const line = lines[i];
    if (!/^\s*["']/.test(line)) break;

    const parts = extractStrings(line);
    if (parts.length === 0) break;
    strings.push(...parts);

    if (/\+\s*(?:\/\/.*)?$/.test(line)) {
      i++;
    } else {
      i++;
      break;
    }
  }

  if (strings.length >= 2) {
    return { value: strings.join(''), endLine: i - 1 };
  }
  return null;
