function looksLikeSecret(str) {
  if (str.length < 8) return false;

  const assembledPatterns = [
    /\b(AKIA[0-9A-Z]{16})\b/,
    /\b(ASIA[0-9A-Z]{16})\b/,
    /\b(AROA[0-9A-Z]{16})\b/,
    /\b(AIDA[0-9A-Z]{16})\b/,
    /\b(sk-[a-zA-Z0-9]{20,})/,
    /\b(pk_[a-zA-Z0-9_]{20,})/,
    /\b(ghp_[a-zA-Z0-9]{36})/,
    /\b(gho_[a-zA-Z0-9]{36})/,
    /\b(ghu_[a-zA-Z0-9]{36})/,
    /\b(ghs_[a-zA-Z0-9]{36})/,
    /\b(ghr_[a-zA-Z0-9]{36})/,
    /\b(AIza[0-9A-Za-z_\-]{35})/,
    /\b(Bearer\s+[a-zA-Z0-9_\-\.]{20,})/,
    /((?:mongodb|postgres|mysql|redis):\/\/[^:]+:[^@]+@)/,
    /-----BEGIN (RSA |EC |DSA |OPENSSH )?PRIVATE KEY-----/,
  ];

  for (const p of assembledPatterns) {
    if (p.test(str)) return true;
  }

  if (/[0-9]/.test(str)) {
    const entropy = getEntropy(str);
    if (str.length >= 16 && entropy > 4.0) return true;
    if (str.length >= 24 && entropy > 3.8) return true;
  }

  return false;
}

// ── Main Check ─────────────────────────────────────────────────────────

export async function check(context) {
  const { tree, files } = context;

  try {
    const envFiles = tree.filter((p) => {
      const name = p.split('/').pop();
      return name.startsWith('.env') && !/\.(example|sample|template|dist)$/.test(name);
