                file: filePath,
                line: i + 1,
                issue: 'Potential hardcoded secret assembled from string concatenation',
              });
            }
            i = ml.endLine;
            continue;
          }

          let m;
          while ((m = inlineConcatRegex.exec(line)) !== null) {
            const parts = [...m[0].matchAll(/"(?:[^"\\]|\\.)*"|'(?:[^'\\]|\\.)*'/g)].map((x) => x[0].slice(1, -1));
            const assembled = parts.join('');
            if (looksLikeSecret(assembled)) {
              findings.push({
                file: filePath,
                line: i + 1,
                issue: 'Potential hardcoded secret assembled from string concatenation',
